import{_ as e,c as o,o as t,b as a}from"./app.7cd0d0a6.js";var r="/assets/logo.04a85aa8.svg";const _='{"title":"Modal interplay","description":"","frontmatter":{"title":"Modal interplay","subtitle":"Exploring the physical, physiological, neurological and psychological links between sight and hearing \u2013 the two main modalities of human perception.","date":"2021-01-19T00:00:00.000Z","cover":"logo.svg"},"headers":[],"relativePath":"theory/color/interplay/index.md"}',n={},i=a('<p>Chromatone is a term composed of two parts. &quot;Chroma&quot; is an Ancient Greek word \u03C7\u03C1\u1FF6\u03BC\u03B1 (khr\xF4ma) and stands for &quot;color&quot;. &quot;Tone&quot; comes from Latin word tonus (&quot;sound&quot;) derived from Ancient Greek \u03C4\u03CC\u03BD\u03BF\u03C2 (t\xF3nos, \u201Cstrain, tension, pitch\u201D). Together they form Chromatone \u2013 the colorful notation system. It&#39;s based on combining the two circular models \u2013 the octave equivalence in music and the color circle of visual arts. This gives not only the colors for each of 12 chromatic notes of modern music, but can be extended to derive a certain color for any acoustic frequency.</p><h1 id="circle-of-colors-and-notes" tabindex="-1">Circle of colors and notes <a class="header-anchor" href="#circle-of-colors-and-notes" aria-hidden="true">#</a></h1><img src="'+r+'"><p>A is the lowest frequency note and red is the lowest frequency color. It\u2019s the starting point. Then we divide the <a href="./spectrum/">Light spectrum</a> into 12 parts and get scientifically correspondent colors for every note in an octave. Now we can see the circle of musical intervals with our eyes and use it to remember all the musical semitones. It may be like an artificial <a href="./synesthesia/">Synesthesia</a> to be developed to improve music learning and performing skills.</p>',4),s=[i];function c(l,d,h,m,u,p){return t(),o("div",null,s)}var g=e(n,[["render",c]]);export{_ as __pageData,g as default};
